const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle, ShadingType, PageBreak } = require('docx');

// Load data from JSON
const data = JSON.parse(fs.readFileSync(__dirname + '/p0_analysis_data.json', 'utf8'));

// Helpers
function headerCell(text, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    shading: { type: ShadingType.SOLID, color: '1a5276' },
    children: [new Paragraph({ children: [new TextRun({ text, bold: true, color: 'FFFFFF', size: 20, font: 'Microsoft YaHei' })], spacing: { before: 40, after: 40 } })],
  });
}

function cell(text, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    children: [new Paragraph({ children: [new TextRun({ text, size: 19, font: 'Microsoft YaHei' })], spacing: { before: 30, after: 30 } })],
  });
}

function heading(text, level) {
  const sizes = {1: 32, 2: 28, 3: 24};
  return new Paragraph({ heading: level, children: [new TextRun({ text, bold: true, font: 'Microsoft YaHei', size: sizes[level] || 24 })], spacing: { before: 200, after: 100 } });
}

function para(text, opts = {}) {
  return new Paragraph({
    children: [new TextRun({ text, size: 21, font: 'Microsoft YaHei', ...opts })],
    spacing: { before: 60, after: 60 }
  });
}

function boldPara(label, text) {
  return new Paragraph({
    children: [
      new TextRun({ text: label, bold: true, size: 21, font: 'Microsoft YaHei' }),
      new TextRun({ text, size: 21, font: 'Microsoft YaHei' })
    ],
    spacing: { before: 40, after: 40 }
  });
}

// Build document
const children = [];

// Title
children.push(
  new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun({ text: '外贸跟进方案 — P0客户完整分析', bold: true, font: 'Microsoft YaHei', size: 36 })], spacing: { after: 100 } }),
  para('生成日期：2026年4月30日'),
  para('数据来源：Okki平台 deep_scrape (2026-04-30T07-40 + 06-12 + cleaned_merged_v2)'),
  para('分析客户：14个P0客户（S级12个，A级2个） | 分析框架：四层渐进判断（SP v4.3）'),
  para(''),
  para('⚠️ 数据交叉验证说明：部分客户仅出现在单一抓取文件中（标注"未经交叉验证"）。31个P0在最新抓取中返回"DOM中未找到"，数据可能有缺失。Karl brown、Abdou Salam Kane、Dania Sanchez、Sarah nell roly、yoselyn Rodriguez 出现在两个以上文件中，数据一致。'),
  para('')
);

// Priority summary
children.push(heading('执行优先级概览', 1));

