    new Paragraph({
      children: [new TextRun({ text: '判断方法：逐条阅读每个客户的完整对话后人工归类，不使用关键词或平台元数据。选中具体客户后可做五步分析和执行方案。', size: 16, color: '888888', font: 'Microsoft YaHei', italics: true })],
