/**
 * 客户状态清单 — Word 文档生成器
 * 只列状态不打方案，用户按需挑客户做深度分析
 * 用法: node gen-status-report.mjs
 */

import { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, HeadingLevel, AlignmentType, WidthType, BorderStyle, ShadingType } from 'docx';
import { writeFileSync, readFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import os from 'os';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const DESKTOP = join(os.homedir(), 'Desktop');

// ============ 系统提示过滤 ============
const SYSTEM_PATTERNS = [
  /automatic reception will no longer intervene/i,
  /由于您介入该会话/i,
  /You have a visitor/i,
  /买家有流失风险/i,
  /AI给您生成了一条回复建议/i,
  /建议查看买家特征/i,
  /阿里国际Marco大模型翻译/i,
  /买家首次给您发消息/i,
  /pre-screened.*clear request/i,
  /一旦离开平台发生纠纷或遭遇欺诈/i,
  /反馈/,
];

function isSystemMsg(msg) {
  if (!msg) return false;
  return SYSTEM_PATTERNS.some(p => p.test(msg));
}

// ============ 数据加载 ============
function loadLatest(prefix) {
  const files = readdirSync(DATA_DIR).filter(f => f.startsWith(prefix) && f.endsWith('.json')).sort().reverse();
  if (files.length === 0) throw new Error('未找到 ' + prefix + ' 数据');
  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf8'));
}

// ============ 加载深抓数据（真实对话） ============
function loadDeepScrapeMessages() {
  const files = readdirSync(DATA_DIR).filter(f => f.startsWith('deep_scrape_v7_') && f.endsWith('.json')).sort().reverse();
  if (files.length === 0) return {};
  const ds = JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf8'));
  const map = {};
  for (const r of (ds.results || [])) {
    const msgs = (r.messages || []).filter(m => m.text && m.text.length > 3);
    const realMsgs = msgs.filter(m => !isSystemMsg(m.text || ''));
    const last = realMsgs.length > 0 ? realMsgs.slice(-2) : msgs.slice(-2);
    map[r.name] = last.map(m => (m.side === 'received' ? '←' : '→') + ': ' + (m.text || '').substring(0, 120)).join('  ');
  }
  return map;
}

function daysAgo(ts) {
  if (!ts) return '?';
  const d = Math.round((Date.now() - ts) / 86400000);
  return d === 0 ? '今天' : d + '天前';
}

// ============ 分类逻辑 ============
function classify(c) {
  const msg = (c.latestMessageContent || '').trim();
  const msgLow = msg.toLowerCase();
  const da = daysAgo(c.lastContactTime);
  const isUnread = c.isUnread || c.unreadCount > 0;
  const isFromUs = c.latestMessageType === 'send';
  const fromCust = c.msgFromCustomer === true;

  // 排除系统提示后的有效客户消息
  const realCustMsg = fromCust && !isSystemMsg(msg) && msg.length > 3;
  const realOurMsg = isFromUs && !isSystemMsg(msg) && msg.length > 3;

  // 关键词
  const hi = /hello|hi\b|how are you|bonjour|hola| salut\b/i.test(msgLow);
  const price = /price|quote|cost|how much|报价|价格|\$[0-9]|usd|dollar|كم|сколько|cuánto/i.test(msgLow);

